actions.script:
def normalize = { it?.toString()?.trim() } def type1 = normalize(file1Type)?.toUpperCase() def type2 = normalize(file2Type)?.toUpperCase() if (!type1 || !type2) throw new IllegalArgumentException("file1Type and file2Type are required")
// Assign ID fields by type def file1IdField = (type1 == "CSV") ? (csvIdField ?: "id") : null def file2IdField = (type2 == "CSV") ? (csvIdField ?: "id") : null def file1IdExpr = (type1 == "JSON") ? (jsonIdField ?: "\$.id") : null def file2IdExpr = (type2 == "JSON") ? (jsonIdField ?: "\$.id") : null
// Assign schema to whichever file is JSON def file1Schema = (type1 == "JSON") ? jsonSchemaFileName : null def file2Schema = (type2 == "JSON") ? jsonSchemaFileName : null
context.unifiedParams = [ file1Location : file1Location, file2Location : file2Location, file1Type : type1, file2Type : type2, file1IdField : file1IdField, file2IdField : file2IdField, file1IdExpression : file1IdExpr, file2IdExpression : file2IdExpr, file1SchemaFileName: file1Schema, file2SchemaFileName: file2Schema, file1Label : file1Label, file2Label : file2Label, hasHeader : hasHeader, outputLocation : outputLocation, outputFileName : outputFileName, sparkMaster : sparkMaster, sparkAppName : sparkAppName ]
